def validate(args, output):
    rows, cols, rc, cc = args
    expected = set()
    for r in range(rows):
        for c in range(cols):
            expected.add((r, c))
    seen = set()
    prev = -1
    for cell in output:
        if not isinstance(cell, list) or len(cell) != 2:
            return False
        r, c = cell[0], cell[1]
        if (r, c) not in expected or (r, c) in seen:
            return False
        seen.add((r, c))
        d = abs(r - rc) + abs(c - cc)
        if d < prev:
            return False
        prev = d
    return seen == expected

