function validate(args, output) {
    const [rows, cols, rc, cc] = args;
    const expected = new Set();
    for (let r = 0; r < rows; r++)
        for (let c = 0; c < cols; c++) expected.add(r + ',' + c);
    const seen = new Set();
    let prev = -1;
    for (const cell of output) {
        if (!Array.isArray(cell) || cell.length !== 2) return false;
        const r = cell[0], c = cell[1];
        const key = r + ',' + c;
        if (!expected.has(key) || seen.has(key)) return false;
        seen.add(key);
        const d = Math.abs(r - rc) + Math.abs(c - cc);
        if (d < prev) return false;
        prev = d;
    }
    if (seen.size !== expected.size) return false;
    for (const k of expected) if (!seen.has(k)) return false;
    return true;
}

