class Solution:
    def allCellsDistOrder(self, rows, cols, rCenter, cCenter):
        # Brute force: bucket cells by distance via BFS-like layering, then
        # flatten in increasing distance with cells sorted within each layer.
        from collections import defaultdict
        buckets = defaultdict(list)
        for r in range(rows):
            for c in range(cols):
                d = abs(r - rCenter) + abs(c - cCenter)
                buckets[d].append([r, c])
        res = []
        for d in sorted(buckets):
            for cell in sorted(buckets[d]):
                res.append(cell)
        return res

